function ThreatMap() {
  const [arcs, setArcs] = useState([]);
  const [blocked, setBlocked] = useState(934);
  const [activeNode, setActiveNode] = useState(null);

  const makeArc = useCallback(() => {
    const src = GEO_NODES.filter(n => n.type === "attack");
    const dst = GEO_NODES.filter(n => n.type === "protected");
    const s = src[Math.floor(Math.random() * src.length)];
    const d = dst[Math.floor(Math.random() * dst.length)];
    const [sx, sy] = lonLatToXY(s.lon, s.lat);
    const [dx, dy] = lonLatToXY(d.lon, d.lat);
    return { id: Date.now() + Math.random(), sx, sy, dx, dy, sLabel: s.label, dLabel: d.label };
  }, []);

  useEffect(() => {
    setArcs([makeArc(), makeArc(), makeArc()]);
    const t = setInterval(() => {
      setArcs(p => [...p.slice(-6), makeArc()]);
      setBlocked(p => p + Math.floor(Math.random() * 2));
    }, 2200);
    return () => clearInterval(t);
  }, [makeArc]);

  return (
    <section id="threatmap" className="section threatmap">
      <div className="container">
        <div className="section__header">
          <div className="section__tag">// Global Threat Intelligence</div>
          <h2>Live Threat Map</h2>
          <p>Real-time visualization of global attack origins and blocked threats across our client network.</p>
        </div>
        <div className="threatmap__wrap glass-card">
          <div className="threatmap__stats">
            <div className="tm-stat"><div className="tm-stat__val green">{blocked}</div><div className="tm-stat__label">Attacks Blocked/hr</div></div>
            <div className="tm-stat"><div className="tm-stat__val yellow">29</div><div className="tm-stat__label">Active Investigations</div></div>
            <div className="tm-stat"><div className="tm-stat__val cyan">99.9%</div><div className="tm-stat__label">Uptime This Month</div></div>
          </div>
          <div className="threatmap__canvas">
            <svg viewBox="0 0 1000 500" className="threatmap__svg" preserveAspectRatio="xMidYMid meet">
              {/* Ocean bg */}
              <rect x="0" y="0" width="1000" height="500" fill="#060e0b"/>
              {/* Grid lines */}
              {[-180,-120,-60,0,60,120,180].map(lon => {
                const [x] = lonLatToXY(lon, 0);
                return <line key={"lon"+lon} x1={x} y1="0" x2={x} y2="500" stroke="rgba(0,255,136,0.04)" strokeWidth="0.5"/>;
              })}
              {[-60,-30,0,30,60].map(lat => {
                const [,y] = lonLatToXY(0, lat);
                return <line key={"lat"+lat} x1="0" y1={y} x2="1000" y2={y} stroke="rgba(0,255,136,0.04)" strokeWidth="0.5"/>;
              })}
              {/* Continents */}
              {CONTINENT_PATHS.map((d, i) => (
                <path key={i} d={d} fill="rgba(0,255,136,0.06)" stroke="rgba(0,255,136,0.2)" strokeWidth="0.8"/>
              ))}
              {/* Attack arcs */}
              {arcs.map(arc => {
                const mx = (arc.sx + arc.dx) / 2;
                const my = Math.min(arc.sy, arc.dy) - Math.abs(arc.dx - arc.sx) * 0.25 - 40;
                return (
                  <g key={arc.id}>
                    <path
                      d={`M${arc.sx},${arc.sy} Q${mx},${my} ${arc.dx},${arc.dy}`}
                      fill="none" stroke="#ff4444" strokeWidth="1" opacity="0.8"
                      className="arc-animate"
                      strokeDasharray="4 2"
                    />
                    <circle cx={arc.dx} cy={arc.dy} r="5" fill="#ff4444" opacity="0.4" className="arc-hit"/>
                  </g>
                );
              })}
              {/* Nodes */}
              {GEO_NODES.map(n => {
                const [x, y] = lonLatToXY(n.lon, n.lat);
                const isAtk = n.type === "attack";
                const col = isAtk ? "#ff4444" : "#00ff88";
                const r = isAtk ? 4 : 5;
                return (
                  <g key={n.label} className="map-node" onClick={() => setActiveNode(activeNode?.label === n.label ? null : n)}>
                    <circle cx={x} cy={y} r={r} fill={col} opacity="0.9"/>
                    <circle cx={x} cy={y} r={r * 2.2} fill={col} opacity="0.12" className="node-pulse"/>
                    <circle cx={x} cy={y} r={r * 3.5} fill={col} opacity="0.05" className="node-pulse-slow"/>
                    <text x={x + r + 4} y={y + 4} fontSize="9" fill={isAtk ? "#ff9999" : "#88ffcc"} opacity="0.85" fontFamily="Share Tech Mono,monospace">{n.label}</text>
                  </g>
                );
              })}
            </svg>
            {/* Tooltip */}
            {activeNode && (
              <div className="map-tooltip">
                <div className={"map-tooltip__type " + (activeNode.type === "attack" ? "red" : "green")}>
                  {activeNode.type === "attack" ? "⚠ Attack Origin" : "✓ Protected Client"}
                </div>
                <div className="map-tooltip__city">{activeNode.label}</div>
                <div className="map-tooltip__coord dim">{activeNode.lat.toFixed(1)}°{activeNode.lat>=0?"N":"S"} {Math.abs(activeNode.lon).toFixed(1)}°{activeNode.lon>=0?"E":"W"}</div>
              </div>
            )}
            <div className="threatmap__legend">
              <span><span className="legend-dot legend-dot--red"/>Attack Origin</span>
              <span><span className="legend-dot legend-dot--green"/>Protected Client</span>
              <span className="dim" style={{fontSize:"11px"}}>Click nodes for details</span>
            </div>
          </div>
        </div>
      </div>
    </section>
  );
}

